import{_ as o,o as t,c as a,au as r}from"./chunks/framework.Bpqx6pAq.js";const p=JSON.parse('{"title":"Catalog hooks","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/hooks/hooks.catalog.md","filePath":"api/map/hooks/hooks.catalog.md"}'),c={name:"api/map/hooks/hooks.catalog.md"};function d(i,e,s,n,l,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="catalog-hooks" tabindex="-1">Catalog hooks <a class="header-anchor" href="#catalog-hooks" aria-label="Permalink to &quot;Catalog hooks&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Hooks for the catalog service: injecting default categories and sublegends from service configuration, filtering query results to layers only, propagating layer renames and removals to referencing contexts and categories, updating projects when layers or views are deleted, and serializing layer filter queries to/from JSON strings.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="filterlayers-hook" tabindex="-1"><code>filterLayers(hook)</code> <a class="header-anchor" href="#filterlayers-hook" aria-label="Permalink to &quot;`filterLayers(hook)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before find</code> hook.</p></blockquote><p>Ensures that <code>find</code> queries return only layer objects by default. When no <code>type</code> filter is present in the query, injects <code>type: { $nin: [&#39;Context&#39;, &#39;Service&#39;, &#39;Category&#39;, &#39;Sublegend&#39;] }</code> to exclude non-layer catalog items.</p><hr><h3 id="getdefaultcategories-hook" tabindex="-1"><code>getDefaultCategories(hook)</code> <a class="header-anchor" href="#getdefaultcategories-hook" aria-label="Permalink to &quot;`getDefaultCategories(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after find</code> hook.</p></blockquote><p>Appends categories defined in <code>service.options.categories</code> to the find result when the query targets the <code>Category</code> type (or has no type filter). Each default category is filtered through the current query conditions (excluding pagination operators) before being added to the result set.</p><hr><h3 id="getdefaultsublegends-hook" tabindex="-1"><code>getDefaultSublegends(hook)</code> <a class="header-anchor" href="#getdefaultsublegends-hook" aria-label="Permalink to &quot;`getDefaultSublegends(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after find</code> hook.</p></blockquote><p>Appends sublegends defined in <code>service.options.sublegends</code> to the find result when the query targets the <code>Sublegend</code> type (or has no type filter). Behaves identically to <code>getDefaultCategories</code> but for sublegend items.</p><hr><h3 id="updatelayerreferences-hook" tabindex="-1"><code>updateLayerReferences(hook)</code> <a class="header-anchor" href="#updatelayerreferences-hook" aria-label="Permalink to &quot;`updateLayerReferences(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after update/patch/remove</code> hook.</p></blockquote><p>Propagates a layer rename or removal to all catalog items (<code>Context</code>, <code>Category</code>) that reference the layer by name in their <code>layers</code> array.</p><ul><li>On <code>update</code> or <code>patch</code>: replaces the old layer name with the new one in each referencing item.</li><li>On <code>remove</code>: removes the layer name from each referencing item&#39;s <code>layers</code> array.</li></ul><p>Requires <code>hook.params.previousItem</code> (set by <a href="./../../core/hooks/hooks.model.html#populatepreviousobjecthook"><code>populatePreviousObject</code></a>) to identify the original layer name and type. No-op when the item is not a layer.</p><hr><h3 id="updateprojects-hook" tabindex="-1"><code>updateProjects(hook)</code> <a class="header-anchor" href="#updateprojects-hook" aria-label="Permalink to &quot;`updateProjects(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after remove</code> hook.</p></blockquote><p>Removes references to a deleted layer or view from all projects in the same service context. For each removed item:</p><ul><li><strong>Layer</strong>: removes it from <code>project.layers</code> matching by <code>_id</code> or <code>name</code>.</li><li><strong>View (Context)</strong>: removes it from <code>project.views</code> matching by <code>_id</code>.</li></ul><p>No-op when no <code>projects</code> service is available in the context.</p><hr><h3 id="convertfilterqueriestostring-hook" tabindex="-1"><code>convertFilterQueriesToString(hook)</code> <a class="header-anchor" href="#convertfilterqueriestostring-hook" aria-label="Permalink to &quot;`convertFilterQueriesToString(hook)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before create/update/patch</code> hook.</p></blockquote><p>Serializes the <code>active</code> and <code>inactive</code> filter query objects on each layer&#39;s <code>filters</code> array to JSON strings before writing to the database. Uses <a href="./../../core/hooks/hooks.model.html"><code>convertToString</code></a> from the core model hooks.</p><hr><h3 id="convertfilterqueriestoobject-hook" tabindex="-1"><code>convertFilterQueriesToObject(hook)</code> <a class="header-anchor" href="#convertfilterqueriestoobject-hook" aria-label="Permalink to &quot;`convertFilterQueriesToObject(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after find/get</code> hook.</p></blockquote><p>Deserializes the <code>active</code> and <code>inactive</code> filter query strings on each layer&#39;s <code>filters</code> array back to JS objects after reading from the database. Uses <a href="./../../core/hooks/hooks.model.html"><code>convertToJson</code></a> from the core model hooks.</p>',35)])])}const f=o(c,[["render",d]]);export{p as __pageData,f as default};
